SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_sctransmrt2 (data_code, bank_code, trandate, seq_tran, seq_no, membership_no, cmember_name, amount, acc_no, member_group_no, c_reference, eng_name, item_type, branch_bank_code, fee_amount, begining_of_contract, branch_id, loan_type, trans_bank_status, item_seq_no) AS SELECT ' ' AS DATA_CODE
  , BANK_CODE
  , ' ' AS TRANDATE
  , ' ' AS SEQ_TRAN
  , null AS SEQ_NO
  , MEMBERSHIP_NO
  , CMEMBER_NAME
  , SUM(AMOUNT )
  , ACC_NO
  , MEMBER_GROUP_NO
  , LOAN_TYPE AS C_REFERENCE
  , '' AS ENG_NAME
  , 'MRT' AS ITEM_TYPE
  , BRANCH_BANK_CODE
  , 0 AS FEE_AMOUNT
  , BEGINING_OF_CONTRACT
  , '01' AS BRANCH_ID
  , LOAN_TYPE
  , TRANS_BANK_STATUS
  ,0 AS  ITEM_SEQ_NO
  FROM 
  ( 
  SELECT  
        sc_fin_money_return.request_bankid as bank_code ,
        sc_fin_money_return.membership_no as membership_no ,
        CASE WHEN  coalesce(sc_fin_money_return.remark::text, '') = '' THEN  owner_name   ELSE sc_fin_money_return.remark END   as cmember_name ,
        sc_fin_money_return.money_return  as amount,
        trim(both sc_fin_money_return.request_bankac)  as  acc_no ,
        sc_mem_m_membership_registered.member_group_no as member_group_no,
        left((trim(both sc_fin_money_return.request_bankac)),3) as branch_bank_code,        
        sc_fin_money_return.paid_date  as begining_of_contract
, 'MRT' as loan_type
,sc_fin_money_return.tran_status as trans_bank_status
    FROM 
        sc_mem_m_membership_registered ,
        sc_mem_m_ucf_prename ,
        sc_fin_money_return ,     
        sc_mem_m_ucf_member_group 
    WHERE 1=1
        and ( sc_mem_m_membership_registered.prename_code = sc_mem_m_ucf_prename.prename_code ) 
        and ( sc_fin_money_return.membership_no = sc_mem_m_membership_registered.membership_no ) 
        and ( sc_mem_m_membership_registered.member_group_no = sc_mem_m_ucf_member_group.member_group_no ) 
        and ( sc_fin_money_return.cancel_status = '0' )
        and ( sc_fin_money_return.return_status = '1' ) 
        and ( sc_fin_money_return.request_method in (  'TRB' )) 


union all
   

      SELECT  
        sc_inv_bill_term_of_payment.bank_id as bank_code ,
        sc_inv_bill.membership_no as membership_no ,
        CASE WHEN  coalesce(sc_inv_bill_term_of_payment.bank_account_name::text, '') = '' THEN  pka_com_function.fp_get_member_name( sc_inv_bill.membership_no )   ELSE sc_inv_bill_term_of_payment.bank_account_name END   as cmember_name ,
        sc_inv_bill_term_of_payment.money_amount  as amount,
        trim(both sc_inv_bill_term_of_payment.no_account_c)  as  acc_no ,
        sc_mem_m_membership_registered.member_group_no as member_group_no,
       left((trim(both sc_inv_bill_term_of_payment.no_account_c)),3) as branch_bank_code,        
        sc_inv_bill_term_of_payment.transfer_date  as begining_of_contract
, 'INV' as loan_type
,sc_inv_bill_term_of_payment.tran_status as trans_bank_status
    FROM 
        sc_mem_m_membership_registered ,
        sc_inv_bill_term_of_payment ,
        sc_inv_bill     
    WHERE 1=1
	and ( sc_inv_bill.membership_no = sc_mem_m_membership_registered.membership_no ) 
	and ( sc_inv_bill.bill_no = sc_inv_bill_term_of_payment.bill_no ) 
      and ( sc_inv_bill_term_of_payment.cancel_status = '0' )
      and ( sc_inv_bill.paid_status = '1' ) 
      and ( sc_inv_bill_term_of_payment.type_term_of_pay in (  'TRB' )) 

) alias25 
WHERE  1=1
/*WHERE*/

--AND BEGINING_OF_CONTRACT  between '27/9/2023' and  '27/9/2023' 
GROUP BY    BANK_CODE
  , MEMBERSHIP_NO
  , CMEMBER_NAME
  , ACC_NO
  , MEMBER_GROUP_NO
  , BRANCH_BANK_CODE
  , BEGINING_OF_CONTRACT
  , LOAN_TYPE
  , TRANS_BANK_STATUS

    ORDER BY 
        MEMBERSHIP_NO ASC;

